window.FUNGAL_QUESTIONS.push(...[{"id":"Q101","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"MCQ","difficulty":"Medium","source":"PDF p. 69","question":{"en":"Which organism most commonly causes pityriasis versicolor?","ar":"ما الكائن الأكثر شيوعًا في التسبب بالنخالية المبرقشة؟"},"options":[{"letter":"A","en":"Malassezia species","ar":"أنواع Malassezia"},{"letter":"B","en":"Trichophyton rubrum","ar":"Trichophyton rubrum"},{"letter":"C","en":"Hortaea werneckii","ar":"Hortaea werneckii"},{"letter":"D","en":"Staphylococcus aureus","ar":"Staphylococcus aureus"}],"correct":"A","explanation":{"en":"Pityriasis versicolor is caused by lipophilic Malassezia yeasts, especially M. furfur and M. globosa.","ar":"تنتج النخالية المبرقشة عن خمائر Malassezia المحبة للدهون، خاصة M. furfur وM. globosa."},"reasoning":{"en":"The sebaceous distribution and lipophilic biology identify Malassezia rather than a dermatophyte.","ar":"التوزيع في المناطق الدهنية وطبيعة الكائن المحبة للدهون يشيران إلى Malassezia لا إلى فطر جلدي."},"image":null},{"id":"Q102","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"MCQ","difficulty":"Easy","source":"PDF p. 69","question":{"en":"What is the classic KOH appearance of pityriasis versicolor?","ar":"ما المظهر الكلاسيكي في فحص KOH للنخالية المبرقشة؟"},"options":[{"letter":"A","en":"Spaghetti and meatballs","ar":"سباجيتي وكرات اللحم"},{"letter":"B","en":"Broad nonseptate hyphae only","ar":"خيوط عريضة غير مقسمة فقط"},{"letter":"C","en":"Coral-red rods","ar":"عصيات حمراء مرجانية"},{"letter":"D","en":"Grape-like cocci","ar":"مكورات كعناقيد العنب"}],"correct":"A","explanation":{"en":"Short hyphae mixed with clusters of round spores produce the classic appearance.","ar":"تنتج الخيوط القصيرة مع تجمعات الأبواغ المستديرة المظهر الكلاسيكي."},"reasoning":{"en":"Both yeast and mycelial forms are visualized in the specimen.","ar":"تظهر في العينة أشكال الخميرة والخيوط الفطرية معًا."},"image":null},{"id":"Q103","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"MCQ","difficulty":"Easy","source":"PDF p. 69","question":{"en":"Which Wood’s lamp finding may be seen in pityriasis versicolor?","ar":"أي نتيجة قد تظهر تحت مصباح وود في النخالية المبرقشة؟"},"options":[{"letter":"A","en":"Yellowish-golden or coppery fluorescence","ar":"فلورة صفراء ذهبية أو نحاسية"},{"letter":"B","en":"Coral-red fluorescence","ar":"فلورة حمراء مرجانية"},{"letter":"C","en":"Bright green hair fluorescence only","ar":"فلورة خضراء للشعر فقط"},{"letter":"D","en":"No possible fluorescence","ar":"لا يمكن حدوث فلورة"}],"correct":"A","explanation":{"en":"Affected areas may show yellowish-green, golden, or coppery fluorescence under Wood’s lamp.","ar":"قد تظهر المناطق المصابة فلورة صفراء مخضرة أو ذهبية أو نحاسية تحت مصباح وود."},"reasoning":{"en":"The fluorescence is supportive but KOH is more definitive when the diagnosis is uncertain.","ar":"الفلورة داعمة، لكن KOH أكثر حسمًا عند عدم وضوح التشخيص."},"image":null},{"id":"Q104","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"MCQ","difficulty":"Easy","source":"PDF p. 70","question":{"en":"Which distribution is most typical of pityriasis versicolor in adults?","ar":"أي توزيع هو الأكثر شيوعًا للنخالية المبرقشة لدى البالغين؟"},"options":[{"letter":"A","en":"Upper trunk, shoulders, neck, and upper arms","ar":"أعلى الجذع والكتفان والرقبة وأعلى الذراعين"},{"letter":"B","en":"Toe webs only","ar":"بين أصابع القدم فقط"},{"letter":"C","en":"Nail matrix only","ar":"مصفوفة الظفر فقط"},{"letter":"D","en":"Palms and soles exclusively","ar":"راحة اليد وأخمص القدم فقط"}],"correct":"A","explanation":{"en":"Malassezia proliferates in sebaceous areas, especially the upper trunk and neck.","ar":"تتكاثر Malassezia في المناطق الدهنية، خاصة أعلى الجذع والرقبة."},"reasoning":{"en":"The oil-rich distribution reflects the organism’s lipophilic requirement.","ar":"يعكس التوزيع الغني بالدهون حاجة الكائن إلى الدهون."},"image":null},{"id":"Q105","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"MCQ","difficulty":"Medium","source":"PDF p. 70","question":{"en":"What is the “scratch” or evoked scale sign?","ar":"ما علامة القشط أو القشور المستثارة؟"},"options":[{"letter":"A","en":"Fine branny scale becomes visible after scraping the lesion","ar":"ظهور قشور نخالية دقيقة بعد كشط الآفة"},{"letter":"B","en":"The lesion bleeds heavily after light touch","ar":"نزف شديد بعد لمس بسيط"},{"letter":"C","en":"Hair pulls out painlessly","ar":"خروج الشعر دون ألم"},{"letter":"D","en":"The nail separates from the bed","ar":"انفصال الظفر عن السرير"}],"correct":"A","explanation":{"en":"Gentle scraping reveals subtle superficial scale and supports active pityriasis versicolor.","ar":"يكشف الكشط اللطيف القشور السطحية الدقيقة ويدعم وجود نخالية مبرقشة نشطة."},"reasoning":{"en":"The scale indicates ongoing stratum-corneum infection, unlike residual pigment alone.","ar":"تشير القشور إلى عدوى نشطة بالطبقة القرنية بخلاف التصبغ المتبقي وحده."},"image":null},{"id":"Q106","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"MCQ","difficulty":"Hard","source":"PDF p. 73","question":{"en":"Which oral antifungal should be avoided because it is ineffective for pityriasis versicolor?","ar":"أي مضاد فطري فموي يجب تجنبه لأنه غير فعال للنخالية المبرقشة؟"},"options":[{"letter":"A","en":"Oral terbinafine","ar":"تيربينافين فموي"},{"letter":"B","en":"Fluconazole","ar":"فلوكونازول"},{"letter":"C","en":"Itraconazole","ar":"إيتراكونازول"},{"letter":"D","en":"None of the above","ar":"لا شيء مما سبق"}],"correct":"A","explanation":{"en":"Oral terbinafine does not achieve effective concentrations in the stratum corneum through sweat for Malassezia disease.","ar":"لا يصل التيربينافين الفموي إلى تركيز فعال في الطبقة القرنية عبر العرق لعلاج Malassezia."},"reasoning":{"en":"Drug efficacy depends not only on spectrum but also on delivery to the infected skin compartment.","ar":"تعتمد الفعالية على الطيف وعلى وصول الدواء إلى حيز الجلد المصاب أيضًا."},"image":null},{"id":"Q107","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"Case","difficulty":"Hard","source":"PDF p. 69","question":{"en":"A young adult in a humid climate has multiple hypopigmented and tan finely scaling patches over the chest and back with mild itching after sweating. What is the diagnosis?","ar":"شاب في مناخ رطب لديه بقع متعددة فاتحة وبنية دقيقة القشور على الصدر والظهر مع حكة بسيطة بعد التعرق. ما التشخيص؟"},"options":[{"letter":"A","en":"Pityriasis versicolor","ar":"النخالية المبرقشة"},{"letter":"B","en":"Vitiligo","ar":"البهاق"},{"letter":"C","en":"Tinea capitis","ar":"سعفة الرأس"},{"letter":"D","en":"Tinea nigra","ar":"السعفة السوداء"}],"correct":"A","explanation":{"en":"Variable pigmentation, fine scale, sebaceous distribution, and heat-related symptoms are classic.","ar":"اختلاف اللون والقشور الدقيقة والتوزيع الدهني وارتباط الأعراض بالحرارة علامات كلاسيكية."},"reasoning":{"en":"Fine scale is the key feature separating active infection from vitiligo.","ar":"القشور الدقيقة هي المفتاح الذي يميز العدوى النشطة عن البهاق."},"image":null},{"id":"Q108","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"Case","difficulty":"Hard","source":"PDF p. 70","question":{"en":"A child has finely scaling hypopigmented patches mainly on the face. KOH shows short hyphae and spores. Which diagnosis fits?","ar":"طفل لديه بقع فاتحة دقيقة القشور تتركز بالوجه، ويظهر KOH خيوطًا قصيرة وأبواغًا. أي تشخيص يناسب؟"},"options":[{"letter":"A","en":"Pityriasis versicolor","ar":"النخالية المبرقشة"},{"letter":"B","en":"Tinea cruris","ar":"سعفة الأرفاغ"},{"letter":"C","en":"Oral thrush","ar":"القلاع الفموي"},{"letter":"D","en":"Onychomycosis","ar":"فطار الأظافر"}],"correct":"A","explanation":{"en":"Facial involvement is relatively more common in children, and the KOH pattern confirms Malassezia.","ar":"تكون إصابة الوجه أكثر شيوعًا نسبيًا لدى الأطفال، ويؤكد نمط KOH وجود Malassezia."},"reasoning":{"en":"Age changes the common distribution but not the diagnostic microscopy.","ar":"يغير العمر التوزيع الشائع لكنه لا يغير الفحص المجهري التشخيصي."},"image":null},{"id":"Q109","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"Case","difficulty":"Hard","source":"PDF p. 73","question":{"en":"After successful treatment, a patient still has pale patches but no scale and a negative KOH. What is the best interpretation?","ar":"بعد علاج ناجح ما زالت لدى المريض بقع فاتحة بلا قشور وKOH سلبي. ما التفسير الأفضل؟"},"options":[{"letter":"A","en":"Residual pigment change, not treatment failure","ar":"تغير صبغي متبقٍ وليس فشل علاج"},{"letter":"B","en":"Definite active infection","ar":"عدوى نشطة مؤكدة"},{"letter":"C","en":"Immediate need for IV antifungal","ar":"حاجة فورية لمضاد فطري وريدي"},{"letter":"D","en":"Bacterial superinfection","ar":"عدوى بكتيرية ثانوية"}],"correct":"A","explanation":{"en":"Repigmentation can take weeks or months after fungal eradication; activity should be assessed by scale and microscopy.","ar":"قد يستغرق عودة اللون أسابيع أو أشهر بعد القضاء على الفطر، ويُقيّم النشاط بالقشور والفحص المجهري."},"reasoning":{"en":"Color recovery lags behind microbiologic cure, so pigment alone is a poor failure marker.","ar":"تتأخر عودة اللون عن الشفاء الميكروبي، لذلك لا يعد اللون وحده مؤشرًا جيدًا للفشل."},"image":null},{"id":"Q110","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"Case","difficulty":"Easy","source":"PDF p. 73","question":{"en":"A recurrent extensive eruption has failed correctly applied ketoconazole shampoo. KOH remains positive. What is an appropriate next approach?","ar":"طفح واسع متكرر لم يستجب لشامبو الكيتوكونازول المستخدم بصورة صحيحة وما زال KOH إيجابيًا. ما النهج التالي المناسب؟"},"options":[{"letter":"A","en":"Use an appropriate oral regimen such as fluconazole or itraconazole","ar":"استخدام نظام فموي مناسب مثل فلوكونازول أو إيتراكونازول"},{"letter":"B","en":"Use oral terbinafine","ar":"استخدام تيربينافين فموي"},{"letter":"C","en":"Use oral ketoconazole","ar":"استخدام كيتوكونازول فموي"},{"letter":"D","en":"Switch to antibacterial cream","ar":"التحول إلى كريم مضاد بكتيري"}],"correct":"A","explanation":{"en":"Systemic fluconazole or itraconazole is appropriate for extensive or refractory confirmed disease.","ar":"يكون الفلوكونازول أو الإيتراكونازول الجهازي مناسبًا للمرض الواسع أو المقاوم المؤكد."},"reasoning":{"en":"Objective active infection and adequate topical adherence justify escalation.","ar":"إثبات العدوى النشطة مع الالتزام الصحيح بالموضعي يبرران التصعيد."},"image":null},{"id":"Q111","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"Case","difficulty":"Medium","source":"PDF p. 74","question":{"en":"A patient has predictable recurrences every summer despite successful treatment. Which prevention strategy is reasonable?","ar":"مريض تنتكس لديه النخالية كل صيف رغم نجاح العلاج. ما استراتيجية الوقاية المعقولة؟"},"options":[{"letter":"A","en":"Monthly selenium sulfide or ketoconazole shampoo applied to susceptible areas","ar":"استخدام شهري لسيلينيوم سلفايد أو شامبو كيتوكونازول على المناطق المعرضة"},{"letter":"B","en":"Daily oral ketoconazole indefinitely","ar":"كيتوكونازول فموي يوميًا دون توقف"},{"letter":"C","en":"Long-term topical steroid","ar":"كورتيزون موضعي طويل المدى"},{"letter":"D","en":"No preventive strategy exists","ar":"لا توجد استراتيجية وقائية"}],"correct":"A","explanation":{"en":"Intermittent topical prophylaxis can reduce seasonal relapse in frequently recurrent disease.","ar":"يمكن للوقاية الموضعية المتقطعة تقليل الانتكاس الموسمي في الحالات كثيرة التكرار."},"reasoning":{"en":"The predictable environmental trigger makes timed prophylaxis rational.","ar":"وجود محفز بيئي متوقع يجعل الوقاية المجدولة منطقية."},"image":null},{"id":"Q112","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"Treatment","difficulty":"Easy","source":"PDF p. 72","question":{"en":"What is a suitable first-line treatment for mild-to-moderate pityriasis versicolor?","ar":"ما علاج الخط الأول المناسب للنخالية المبرقشة البسيطة إلى المتوسطة؟"},"options":[{"letter":"A","en":"Ketoconazole shampoo or another topical antifungal","ar":"شامبو كيتوكونازول أو مضاد فطري موضعي آخر"},{"letter":"B","en":"Oral amphotericin B","ar":"أمفوتيريسين ب فموي"},{"letter":"C","en":"Topical antibiotic alone","ar":"مضاد حيوي موضعي وحده"},{"letter":"D","en":"High-potency steroid","ar":"كورتيزون قوي"}],"correct":"A","explanation":{"en":"Topical azoles or selenium sulfide are effective and preferred for most localized cases.","ar":"تعد الأزولات الموضعية أو سيلينيوم سلفايد فعالة ومفضلة لمعظم الحالات الموضعية."},"reasoning":{"en":"Superficial widespread skin involvement is accessible to wash or topical therapy.","ar":"الإصابة السطحية المنتشرة على الجلد يمكن الوصول إليها بالشامبو أو العلاج الموضعي."},"image":null},{"id":"Q113","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"Treatment","difficulty":"Hard","source":"PDF p. 72","question":{"en":"How should selenium sulfide 2.5% be used in the regimen described in the chapter?","ar":"كيف يُستخدم سيلينيوم سلفايد 2.5% في النظام المذكور بالفصل؟"},"options":[{"letter":"A","en":"Apply daily, leave for about 10 minutes, then rinse for one week","ar":"يوضع يوميًا ويترك نحو 10 دقائق ثم يشطف لمدة أسبوع"},{"letter":"B","en":"Swallow once daily","ar":"يُبتلع مرة يوميًا"},{"letter":"C","en":"Apply to nails once monthly only","ar":"يوضع على الأظافر مرة شهريًا فقط"},{"letter":"D","en":"Use as an eye drop","ar":"يستخدم كقطرة عين"}],"correct":"A","explanation":{"en":"Contact time is needed for the topical agent to act on Malassezia in the stratum corneum.","ar":"يلزم وقت تماس ليعمل الدواء الموضعي على Malassezia في الطبقة القرنية."},"reasoning":{"en":"Correct application technique is as important as selecting the correct drug.","ar":"طريقة الاستخدام الصحيحة مهمة بقدر اختيار الدواء الصحيح."},"image":null},{"id":"Q114","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"Treatment","difficulty":"Medium","source":"PDF p. 73","question":{"en":"Which oral regimen is presented as a preferred option for extensive disease?","ar":"أي نظام فموي قُدم كخيار مفضل للمرض الواسع؟"},"options":[{"letter":"A","en":"Fluconazole 300 mg once weekly for 2 weeks","ar":"فلوكونازول 300 مجم مرة أسبوعيًا لمدة أسبوعين"},{"letter":"B","en":"Terbinafine 250 mg daily for 6 weeks","ar":"تيربينافين 250 مجم يوميًا 6 أسابيع"},{"letter":"C","en":"Griseofulvin 500 mg once","ar":"جريزوفولفين 500 مجم مرة واحدة"},{"letter":"D","en":"Oral ketoconazole 400 mg once","ar":"كيتوكونازول فموي 400 مجم مرة"}],"correct":"A","explanation":{"en":"Fluconazole is listed as the preferred oral option for extensive or failed topical treatment.","ar":"ذُكر الفلوكونازول كخيار فموي مفضل للمرض الواسع أو فشل العلاج الموضعي."},"reasoning":{"en":"The alternatives listed are ineffective or unsafe for this indication.","ar":"البدائل المذكورة إما غير فعالة أو غير آمنة لهذا الاستعمال."},"image":null},{"id":"Q115","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"Treatment","difficulty":"Medium","source":"PDF p. 73","question":{"en":"Which systemic drug should not be used because of serious safety concerns despite antifungal activity?","ar":"أي دواء جهازي يجب عدم استخدامه بسبب مخاطر أمان خطيرة رغم نشاطه المضاد للفطريات؟"},"options":[{"letter":"A","en":"Oral ketoconazole","ar":"كيتوكونازول فموي"},{"letter":"B","en":"Topical ketoconazole","ar":"كيتوكونازول موضعي"},{"letter":"C","en":"Topical clotrimazole","ar":"كلوتريمازول موضعي"},{"letter":"D","en":"Selenium sulfide shampoo","ar":"شامبو سيلينيوم سلفايد"}],"correct":"A","explanation":{"en":"Oral ketoconazole is avoided because of hepatotoxicity and endocrine adverse effects; topical formulations remain useful.","ar":"يُتجنب الكيتوكونازول الفموي بسبب سمية الكبد والآثار الهرمونية، بينما تظل الأشكال الموضعية مفيدة."},"reasoning":{"en":"Route changes systemic exposure and risk, so oral and topical ketoconazole are not interchangeable.","ar":"يغير طريق الإعطاء التعرض الجهازي والخطر، فلا يتساوى الفموي والموضعي."},"image":null},{"id":"Q116","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"Treatment","difficulty":"Medium","source":"PDF p. 74","question":{"en":"Topical monthly prophylaxis fails in a patient with frequent recurrences. Which oral prophylaxis is described?","ar":"فشلت الوقاية الموضعية الشهرية لدى مريض كثير الانتكاس. أي وقاية فموية موصوفة؟"},"options":[{"letter":"A","en":"Itraconazole 200 mg twice daily for one day each month","ar":"إيتراكونازول 200 مجم مرتين في يوم واحد كل شهر"},{"letter":"B","en":"Fluconazole daily for life","ar":"فلوكونازول يوميًا مدى الحياة"},{"letter":"C","en":"Oral ketoconazole weekly","ar":"كيتوكونازول فموي أسبوعيًا"},{"letter":"D","en":"Terbinafine once monthly","ar":"تيربينافين مرة شهريًا"}],"correct":"A","explanation":{"en":"Intermittent itraconazole is an alternative when topical prophylaxis is unsuitable or ineffective.","ar":"الإيتراكونازول المتقطع بديل عند عدم ملاءمة الوقاية الموضعية أو فشلها."},"reasoning":{"en":"Systemic prophylaxis is reserved for selected recurrent cases because of interactions and adverse effects.","ar":"تُحجز الوقاية الجهازية لحالات متكررة مختارة بسبب التداخلات والآثار الجانبية."},"image":null},{"id":"Q117","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"Image","difficulty":"Medium","source":"PDF p. 69","question":{"en":"The image shows multiple hypopigmented finely scaling macules on the trunk. Which diagnosis is most likely?","ar":"توضح الصورة بقعًا متعددة فاتحة دقيقة القشور على الجذع. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Pityriasis versicolor","ar":"النخالية المبرقشة"},{"letter":"B","en":"Vitiligo","ar":"البهاق"},{"letter":"C","en":"Tinea nigra","ar":"السعفة السوداء"},{"letter":"D","en":"Cellulitis","ar":"التهاب النسيج الخلوي"}],"correct":"A","explanation":{"en":"The multifocal trunk distribution and subtle scale are typical of Malassezia infection.","ar":"التوزيع المتعدد على الجذع والقشور الدقيقة نموذجيان لعدوى Malassezia."},"reasoning":{"en":"Scale and coalescing macules distinguish it from completely non-scaling depigmentation.","ar":"القشور واندماج البقع يميزانها عن فقد الصبغة غير المتقشر."},"image":"assets/images/chapters/fungal/fungal-q117.webp"},{"id":"Q118","topic":"pityriasis-versicolor","topicEn":"Pityriasis Versicolor","topicAr":"النخالية المبرقشة","type":"Image","difficulty":"Hard","source":"PDF p. 69","question":{"en":"In a patient with the pictured lesions, which bedside sign would best demonstrate active disease?","ar":"في مريض لديه الآفات المصورة، أي علامة سريرية تُظهر نشاط المرض بصورة أفضل؟"},"options":[{"letter":"A","en":"Evoked fine scale after scratching","ar":"ظهور قشور دقيقة بعد الحك"},{"letter":"B","en":"Positive Nikolsky sign","ar":"علامة نيكولسكي إيجابية"},{"letter":"C","en":"Fluctuation","ar":"تذبذب"},{"letter":"D","en":"Pitting edema","ar":"وذمة انطباعية"}],"correct":"A","explanation":{"en":"The scratch sign reveals branny scale that may be difficult to see at rest.","ar":"تكشف علامة الحك القشور النخالية التي قد يصعب رؤيتها دون تحفيز."},"reasoning":{"en":"Demonstrating scale helps confirm ongoing stratum-corneum involvement.","ar":"إظهار القشور يساعد على تأكيد استمرار إصابة الطبقة القرنية."},"image":"assets/images/chapters/fungal/fungal-q118.webp"},{"id":"Q119","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"MCQ","difficulty":"Easy","source":"PDF p. 76","question":{"en":"Which microscopic finding supports candidiasis?","ar":"أي نتيجة مجهرية تدعم تشخيص داء المبيضات؟"},"options":[{"letter":"A","en":"Budding yeast cells with pseudohyphae","ar":"خلايا خميرية متبرعمة مع خيوط كاذبة"},{"letter":"B","en":"Only long dermatophyte hyphae without yeast","ar":"خيوط فطرية جلدية طويلة فقط دون خميرة"},{"letter":"C","en":"Acid-fast bacilli","ar":"عصيات مقاومة للحمض"},{"letter":"D","en":"Gram-negative diplococci only","ar":"مكورات مزدوجة سالبة الجرام فقط"}],"correct":"A","explanation":{"en":"Candida commonly appears as budding yeast with pseudohyphal forms on KOH or Gram stain.","ar":"تظهر Candida عادةً كخلايا خميرية متبرعمة مع خيوط كاذبة في KOH أو صبغة جرام."},"reasoning":{"en":"The mixed yeast-pseudohypha morphology reflects pathogenic transition from commensal yeast growth.","ar":"يعكس وجود الخميرة والخيوط الكاذبة التحول الممرض من الاستعمار الطبيعي."},"image":null},{"id":"Q120","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"MCQ","difficulty":"Medium","source":"PDF p. 76","question":{"en":"Which finding is most typical of candidal intertrigo?","ar":"أي علامة هي الأكثر شيوعًا في التهاب الثنيات بالمبيضات؟"},"options":[{"letter":"A","en":"Moist glazed erythema with satellite papules or pustules","ar":"حمامى رطبة لامعة مع حطاطات أو بثور تابعة"},{"letter":"B","en":"Dry annular plaque with complete central clearing and no satellites","ar":"لويحة حلقية جافة مع تفريغ مركزي كامل دون آفات تابعة"},{"letter":"C","en":"Black asymptomatic palmar macule","ar":"بقعة سوداء غير عرضية براحة اليد"},{"letter":"D","en":"Scaly alopecia","ar":"فقد شعر متقشر"}],"correct":"A","explanation":{"en":"Candidal intertrigo is red, moist, macerated, and commonly surrounded by satellite lesions.","ar":"التهاب الثنيات بالمبيضات أحمر ورطب ومتميع، وغالبًا تحيط به آفات تابعة."},"reasoning":{"en":"Moisture plus satellites differentiates Candida from many other fold disorders.","ar":"الرطوبة مع الآفات التابعة تميز المبيضات عن كثير من أمراض الثنيات."},"image":null},{"id":"Q121","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"MCQ","difficulty":"Easy","source":"PDF p. 77","question":{"en":"Erosio-interdigitalis blastomycetica most commonly affects which site?","ar":"أي موقع يُصاب غالبًا في Erosio-interdigitalis blastomycetica؟"},"options":[{"letter":"A","en":"The web between the middle and ring fingers","ar":"الفراغ بين الإصبع الأوسط والبنصر"},{"letter":"B","en":"The scalp vertex","ar":"قمة فروة الرأس"},{"letter":"C","en":"The great toenail matrix","ar":"مصفوفة ظفر إصبع القدم الكبير"},{"letter":"D","en":"The upper back only","ar":"أعلى الظهر فقط"}],"correct":"A","explanation":{"en":"This Candida-associated erosion occurs in chronically wet interdigital spaces, especially in wet-work occupations.","ar":"يحدث هذا التآكل المرتبط بالكانديدا في الفراغات بين الأصابع المعرضة للماء مزمنًا، خاصة في أعمال البلل."},"reasoning":{"en":"The exposure history and characteristic finger web identify the condition.","ar":"تاريخ التعرض للماء والفراغ المميز بين الأصابع يحددان الحالة."},"image":null},{"id":"Q122","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"MCQ","difficulty":"Medium","source":"PDF p. 77","question":{"en":"What happens when oral thrush plaques are scraped?","ar":"ماذا يحدث عند كشط لويحات القلاع الفموي؟"},"options":[{"letter":"A","en":"They reveal an erythematous friable mucosa","ar":"تكشف مخاطية حمراء هشة"},{"letter":"B","en":"They leave completely normal dry skin","ar":"تترك جلدًا جافًا طبيعيًا تمامًا"},{"letter":"C","en":"They expose a black eschar","ar":"تكشف قشرة سوداء"},{"letter":"D","en":"They cannot be removed under any circumstance","ar":"لا يمكن إزالتها مطلقًا"}],"correct":"A","explanation":{"en":"The curd-like pseudomembranes can be removed, exposing inflamed red mucosa beneath.","ar":"يمكن إزالة الأغشية الكاذبة الشبيهة بالجبن فتظهر مخاطية ملتهبة حمراء أسفلها."},"reasoning":{"en":"Scrapability helps distinguish thrush from fixed keratotic white lesions.","ar":"قابلية الكشط تساعد على تمييز القلاع عن الآفات البيضاء الكيراتينية الثابتة."},"image":null},{"id":"Q123","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"MCQ","difficulty":"Medium","source":"PDF p. 84","question":{"en":"Which patient with Candida detected vaginally should generally receive treatment?","ar":"أي مريضة وُجدت لديها Candida مهبليًا يجب علاجها عادةً؟"},"options":[{"letter":"A","en":"A symptomatic patient with laboratory evidence of infection","ar":"مريضة لديها أعراض مع دليل معملي على العدوى"},{"letter":"B","en":"An asymptomatic patient with Candida on a Pap smear only","ar":"مريضة بلا أعراض وظهرت Candida في مسحة عنق الرحم فقط"},{"letter":"C","en":"Every colonized woman regardless of symptoms","ar":"كل امرأة مستعمرة دون اعتبار للأعراض"},{"letter":"D","en":"Only patients with fever","ar":"المريضات المصابات بحمى فقط"}],"correct":"A","explanation":{"en":"Asymptomatic vaginal colonization is common and does not require treatment; symptoms plus evidence support VVC therapy.","ar":"الاستعمار المهبلي دون أعراض شائع ولا يحتاج علاجًا؛ وجود الأعراض مع الدليل يدعم علاج التهاب المهبل بالمبيضات."},"reasoning":{"en":"Treatment should target disease, not colonization.","ar":"يجب أن يستهدف العلاج المرض لا مجرد الاستعمار."},"image":null},{"id":"Q124","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"MCQ","difficulty":"Hard","source":"PDF p. 85","question":{"en":"Which regimen is preferred for vulvovaginal candidiasis during pregnancy?","ar":"أي نظام مفضل لالتهاب المهبل بالمبيضات أثناء الحمل؟"},"options":[{"letter":"A","en":"A topical azole for 7 days","ar":"أزول موضعي لمدة 7 أيام"},{"letter":"B","en":"Oral fluconazole 150 mg once","ar":"فلوكونازول فموي 150 مجم مرة"},{"letter":"C","en":"Vaginal boric acid","ar":"حمض البوريك مهبليًا"},{"letter":"D","en":"Oteseconazole","ar":"أوتيسيكونازول"}],"correct":"A","explanation":{"en":"Pregnancy is treated with a full topical azole course; oral fluconazole and boric acid are avoided because of fetal risk.","ar":"يُعالج الحمل بدورة كاملة من أزول موضعي، ويُتجنب الفلوكونازول الفموي وحمض البوريك بسبب خطر الجنين."},"reasoning":{"en":"Safety constraints change the route even when oral therapy is convenient outside pregnancy.","ar":"تغير قيود الأمان طريق العلاج رغم سهولة العلاج الفموي خارج الحمل."},"image":null},{"id":"Q125","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"MCQ","difficulty":"Easy","source":"PDF p. 88","question":{"en":"How is recurrent vulvovaginal candidiasis defined in the chapter?","ar":"كيف يُعرّف التهاب المهبل بالمبيضات المتكرر في الفصل؟"},"options":[{"letter":"A","en":"Three or more symptomatic episodes within one year","ar":"ثلاث نوبات عرضية أو أكثر خلال سنة"},{"letter":"B","en":"One episode every five years","ar":"نوبة واحدة كل خمس سنوات"},{"letter":"C","en":"Any asymptomatic positive culture","ar":"أي مزرعة إيجابية بلا أعراض"},{"letter":"D","en":"Two episodes during a lifetime","ar":"نوبتان طوال العمر"}],"correct":"A","explanation":{"en":"The updated definition is at least three symptomatic episodes in one year.","ar":"التعريف المحدث هو ثلاث نوبات عرضية على الأقل خلال عام واحد."},"reasoning":{"en":"Frequency and symptoms—not colonization—establish the recurrent syndrome.","ar":"التكرار مع الأعراض لا الاستعمار هو ما يثبت المتلازمة المتكررة."},"image":null},{"id":"Q126","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"MCQ","difficulty":"Easy","source":"PDF p. 87","question":{"en":"Which Candida species is often intrinsically less susceptible to azoles and may require boric acid or compounded therapy?","ar":"أي نوع من Candida يكون غالبًا أقل حساسية للأزولات وقد يحتاج حمض البوريك أو علاجًا مركبًا؟"},"options":[{"letter":"A","en":"Candida glabrata","ar":"Candida glabrata"},{"letter":"B","en":"Candida albicans in every case","ar":"Candida albicans في كل الحالات"},{"letter":"C","en":"Malassezia globosa","ar":"Malassezia globosa"},{"letter":"D","en":"Trichophyton tonsurans","ar":"Trichophyton tonsurans"}],"correct":"A","explanation":{"en":"C. glabrata often responds poorly to fluconazole and may need boric acid, nystatin, or compounded flucytosine/amphotericin regimens.","ar":"غالبًا تستجيب C. glabrata بصورة ضعيفة للفلوكونازول وقد تحتاج حمض البوريك أو النيستاتين أو مستحضرات فلوسيتوزين/أمفوتيريسين مركبة."},"reasoning":{"en":"Species identification becomes crucial when standard azole therapy fails.","ar":"يصبح تحديد النوع ضروريًا عند فشل العلاج المعتاد بالأزول."},"image":null},{"id":"Q127","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"Case","difficulty":"Easy","source":"PDF p. 76","question":{"en":"An obese diabetic patient has a painful moist red rash beneath the breasts with peeling borders and small pustules beyond the main plaque. What is the diagnosis?","ar":"مريض بدين مصاب بالسكري لديه طفح أحمر رطب مؤلم تحت الثدي مع حواف مقشرة وبثور صغيرة خارج اللويحة الرئيسية. ما التشخيص؟"},"options":[{"letter":"A","en":"Candidal intertrigo","ar":"التهاب الثنيات بالمبيضات"},{"letter":"B","en":"Tinea capitis","ar":"سعفة الرأس"},{"letter":"C","en":"Tinea nigra","ar":"السعفة السوداء"},{"letter":"D","en":"Onychomycosis","ar":"فطار الأظافر"}],"correct":"A","explanation":{"en":"A moist fold, major risk factors, glazed erythema, and satellite pustules strongly indicate candidal intertrigo.","ar":"الثنية الرطبة وعوامل الخطورة والحمامى اللامعة والبثور التابعة تشير بقوة إلى التهاب الثنيات بالمبيضات."},"reasoning":{"en":"The satellites are the decisive morphological clue.","ar":"البثور التابعة هي العلامة الشكلية الحاسمة."},"image":null},{"id":"Q128","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"Case","difficulty":"Medium","source":"PDF p. 77","question":{"en":"A dishwasher develops recurrent white maceration and a central erosion between the middle and ring fingers. What is the likely diagnosis?","ar":"عامل غسيل أطباق أصيب بتميع أبيض متكرر وتآكل مركزي بين الإصبع الأوسط والبنصر. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Erosio-interdigitalis blastomycetica","ar":"Erosio-interdigitalis blastomycetica"},{"letter":"B","en":"Tinea capitis","ar":"سعفة الرأس"},{"letter":"C","en":"Pityriasis versicolor","ar":"النخالية المبرقشة"},{"letter":"D","en":"DLSO","ar":"فطار تحت الظفر البعيد الجانبي"}],"correct":"A","explanation":{"en":"Chronic wet work and the characteristic interdigital site support Candida-associated erosio.","ar":"العمل الرطب المزمن والموقع المميز بين الأصابع يدعمان تآكلًا مرتبطًا بالكانديدا."},"reasoning":{"en":"Exposure and location make the diagnosis more specific than generic hand eczema.","ar":"التعرض والموقع يجعلان التشخيص أكثر نوعية من إكزيما اليد العامة."},"image":null},{"id":"Q129","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"Case","difficulty":"Easy","source":"PDF p. 77","question":{"en":"An elderly denture wearer has creamy white oral plaques that scrape off, leaving a red tender surface. What is the most likely diagnosis?","ar":"مسن يرتدي طقم أسنان لديه لويحات فموية بيضاء كريمية تُكشط وتترك سطحًا أحمر مؤلمًا. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Oral candidiasis","ar":"داء المبيضات الفموي"},{"letter":"B","en":"Oral leukoplakia","ar":"الطلاوة الفموية"},{"letter":"C","en":"Tinea nigra","ar":"السعفة السوداء"},{"letter":"D","en":"Aphthous stomatitis","ar":"التهاب الفم القلاعي"}],"correct":"A","explanation":{"en":"Scrapable curd-like plaques plus denture use are classic for thrush.","ar":"اللويحات الشبيهة بالجبن القابلة للكشط مع استخدام طقم الأسنان علامات كلاسيكية للقلاع."},"reasoning":{"en":"A fixed white premalignant lesion would not typically scrape off.","ar":"الآفة البيضاء الثابتة قبل السرطانية لا تُكشط عادةً."},"image":null},{"id":"Q130","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"Case","difficulty":"Medium","source":"PDF p. 82","question":{"en":"An adult using an inhaled corticosteroid develops mild oral thrush. Which modifiable factor should be addressed?","ar":"بالغ يستخدم كورتيزونًا مستنشقًا وأصيب بقلاع فموي بسيط. أي عامل قابل للتعديل يجب معالجته؟"},"options":[{"letter":"A","en":"Rinse the mouth after inhalation and use a spacer when appropriate","ar":"مضمضة الفم بعد الاستنشاق واستخدام spacer عند الملاءمة"},{"letter":"B","en":"Stop all asthma therapy abruptly","ar":"إيقاف كل علاج الربو فجأة"},{"letter":"C","en":"Avoid brushing teeth","ar":"تجنب تنظيف الأسنان"},{"letter":"D","en":"Use systemic antibiotics","ar":"استخدام مضادات حيوية جهازية"}],"correct":"A","explanation":{"en":"Reducing oropharyngeal steroid deposition lowers recurrent Candida risk without abandoning necessary respiratory treatment.","ar":"تقليل ترسب الكورتيزون بالفم والبلعوم يخفض خطر تكرار الكانديدا دون التخلي عن علاج التنفس الضروري."},"reasoning":{"en":"Risk-factor correction should accompany antifungal treatment.","ar":"يجب أن يصاحب تصحيح عامل الخطورة العلاج المضاد للفطريات."},"image":null},{"id":"Q131","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"Case","difficulty":"Medium","source":"PDF p. 84","question":{"en":"A healthy nonpregnant woman has intense vulvar itching and thick curd-like discharge, microscopy confirms Candida, and she has had no prior episodes this year. How is this classified?","ar":"امرأة سليمة غير حامل لديها حكة شديدة وإفرازات كثيفة متجبنة، وأكد الفحص Candida ولم تحدث نوبات سابقة هذا العام. كيف تصنف؟"},"options":[{"letter":"A","en":"Uncomplicated VVC","ar":"التهاب مهبل بالمبيضات غير معقد"},{"letter":"B","en":"Recurrent VVC","ar":"التهاب متكرر"},{"letter":"C","en":"Asymptomatic colonization","ar":"استعمار بلا أعراض"},{"letter":"D","en":"Invasive candidiasis","ar":"داء مبيضات غازي"}],"correct":"A","explanation":{"en":"Sporadic mild-to-moderate disease in an immunocompetent nonpregnant patient is uncomplicated VVC.","ar":"المرض المتقطع البسيط إلى المتوسط لدى مريضة سليمة المناعة وغير حامل يُعد غير معقد."},"reasoning":{"en":"Classification guides the duration and route of therapy.","ar":"يحدد التصنيف مدة العلاج وطريقه."},"image":null},{"id":"Q132","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"Case","difficulty":"Medium","source":"PDF p. 85","question":{"en":"A pregnant patient with symptomatic confirmed VVC asks for a single oral fluconazole tablet. What is the best response?","ar":"مريضة حامل لديها التهاب مهبل بالمبيضات مؤكد وأعراض وتطلب قرص فلوكونازول واحدًا. ما الرد الأفضل؟"},"options":[{"letter":"A","en":"Use a 7-day topical azole instead","ar":"استخدام أزول موضعي لمدة 7 أيام بدلًا منه"},{"letter":"B","en":"Oral fluconazole is preferred in pregnancy","ar":"الفلوكونازول الفموي مفضل في الحمل"},{"letter":"C","en":"Use vaginal boric acid","ar":"استخدام حمض البوريك مهبليًا"},{"letter":"D","en":"No treatment can be used in pregnancy","ar":"لا يمكن استخدام أي علاج في الحمل"}],"correct":"A","explanation":{"en":"Topical azoles are preferred in pregnancy; oral fluconazole is avoided because of miscarriage and fetal safety concerns.","ar":"تُفضل الأزولات الموضعية في الحمل ويُتجنب الفلوكونازول الفموي بسبب مخاطر الإجهاض وسلامة الجنين."},"reasoning":{"en":"Pregnancy changes the acceptable risk profile even for a common single-dose regimen.","ar":"يغير الحمل مستوى الخطر المقبول حتى مع نظام جرعة واحدة شائع."},"image":null},{"id":"Q133","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"Case","difficulty":"Medium","source":"PDF p. 87","question":{"en":"A nonpregnant patient has persistent symptomatic C. glabrata VVC after azole failure. Which counseling point is essential if boric acid is selected?","ar":"مريضة غير حامل لديها التهاب مهبل عرضي مستمر بـ C. glabrata بعد فشل الأزول. ما النصيحة الأساسية إذا اختير حمض البوريك؟"},"options":[{"letter":"A","en":"Use only intravaginally and never swallow because ingestion can be fatal","ar":"يستخدم مهبليًا فقط ولا يُبتلع لأن الابتلاع قد يكون قاتلًا"},{"letter":"B","en":"It is safe to take orally with food","ar":"آمن للابتلاع مع الطعام"},{"letter":"C","en":"It is preferred during pregnancy","ar":"مفضل في الحمل"},{"letter":"D","en":"Stop after one night regardless of response","ar":"إيقافه بعد ليلة واحدة دائمًا"}],"correct":"A","explanation":{"en":"Boric acid can be effective for azole-resistant non-albicans VVC but is toxic orally and contraindicated in pregnancy.","ar":"قد يكون حمض البوريك فعالًا للأنواع غير الألبكان المقاومة للأزول لكنه سام عند الابتلاع وممنوع في الحمل."},"reasoning":{"en":"The route and safety warning are as important as the antifungal selection.","ar":"طريق الاستخدام والتحذير الأمني مهمان بقدر اختيار الدواء."},"image":null},{"id":"Q134","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"Case","difficulty":"Easy","source":"PDF p. 89","question":{"en":"A nonpregnant woman has four laboratory-confirmed symptomatic VVC episodes in one year. What therapeutic strategy is appropriate?","ar":"امرأة غير حامل لديها أربع نوبات عرضية مؤكدة معمليًا خلال سنة. ما الاستراتيجية العلاجية المناسبة؟"},"options":[{"letter":"A","en":"Induction therapy followed by prolonged weekly suppression","ar":"علاج استهلالي يتبعه تثبيط أسبوعي طويل"},{"letter":"B","en":"Treat only the current episode with one topical application","ar":"علاج النوبة الحالية بتطبيق موضعي واحد فقط"},{"letter":"C","en":"No treatment because Candida may colonize","ar":"لا علاج لأن Candida قد تستعمر"},{"letter":"D","en":"Continuous antibacterial prophylaxis","ar":"وقاية مستمرة بمضاد بكتيري"}],"correct":"A","explanation":{"en":"RVVC is managed by achieving initial control and then maintaining suppression, commonly with fluconazole in eligible nonpregnant patients.","ar":"يعالج الالتهاب المتكرر بالسيطرة الأولية ثم التثبيط المستمر، غالبًا بالفلوكونازول لدى غير الحوامل المناسبات."},"reasoning":{"en":"Repeated isolated short courses do not address the high relapse tendency.","ar":"الدورات القصيرة المنفصلة لا تعالج الميل المرتفع للانتكاس."},"image":null},{"id":"Q135","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"Treatment","difficulty":"Easy","source":"PDF p. 79","question":{"en":"What is the preferred first-line treatment for mild oral thrush in an immunocompetent infant aged 1–11 months?","ar":"ما علاج الخط الأول المفضل للقلاع الفموي البسيط لدى رضيع سليم المناعة عمره 1–11 شهرًا؟"},"options":[{"letter":"A","en":"Nystatin suspension 200,000 units four times daily for 7–14 days","ar":"نيستاتين معلق 200000 وحدة أربع مرات يوميًا لمدة 7–14 يومًا"},{"letter":"B","en":"Oral ketoconazole","ar":"كيتوكونازول فموي"},{"letter":"C","en":"IV amphotericin B routinely","ar":"أمفوتيريسين ب وريدي روتينيًا"},{"letter":"D","en":"Topical terbinafine","ar":"تيربينافين موضعي"}],"correct":"A","explanation":{"en":"Nystatin is inexpensive, locally acting, and commonly recommended first for mild infant thrush.","ar":"النيستاتين منخفض التكلفة ويعمل موضعيًا ويُوصى به غالبًا أولًا للقلاع البسيط لدى الرضع."},"reasoning":{"en":"Systemic therapy is reserved for refractory disease or immunocompromise.","ar":"يُحجز العلاج الجهازي للحالات المقاومة أو ضعف المناعة."},"image":null},{"id":"Q136","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"Treatment","difficulty":"Hard","source":"PDF p. 83","question":{"en":"What is appropriate for moderate-to-severe oral candidiasis in an immunocompromised adult?","ar":"ما العلاج المناسب لداء المبيضات الفموي المتوسط إلى الشديد لدى بالغ ضعيف المناعة؟"},"options":[{"letter":"A","en":"Fluconazole 100–200 mg orally daily for 7–14 days","ar":"فلوكونازول 100–200 مجم فمويًا يوميًا لمدة 7–14 يومًا"},{"letter":"B","en":"Topical powder on the skin","ar":"بودرة موضعية على الجلد"},{"letter":"C","en":"Single nystatin dose","ar":"جرعة واحدة من النيستاتين"},{"letter":"D","en":"No treatment","ar":"دون علاج"}],"correct":"A","explanation":{"en":"Systemic therapy is recommended when disease is moderate/severe or host immunity is impaired.","ar":"يوصى بالعلاج الجهازي عندما يكون المرض متوسطًا أو شديدًا أو تكون المناعة ضعيفة."},"reasoning":{"en":"Severity and risk of esophageal extension justify systemic exposure.","ar":"الشدة وخطر امتداد العدوى للمريء يبرران العلاج الجهازي."},"image":null},{"id":"Q137","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"Treatment","difficulty":"Hard","source":"PDF p. 89","question":{"en":"Which fluconazole regimen is described for recurrent VVC in an eligible nonpregnant patient?","ar":"أي نظام فلوكونازول موصوف لالتهاب المهبل المتكرر لدى مريضة غير حامل مناسبة؟"},"options":[{"letter":"A","en":"150 mg on days 1, 4, and 7, then 150 mg weekly for 6 months","ar":"150 مجم أيام 1 و4 و7 ثم 150 مجم أسبوعيًا لمدة 6 أشهر"},{"letter":"B","en":"150 mg once only with no follow-up","ar":"150 مجم مرة واحدة فقط دون متابعة"},{"letter":"C","en":"Daily for life","ar":"يوميًا مدى الحياة"},{"letter":"D","en":"One topical dose yearly","ar":"جرعة موضعية واحدة سنويًا"}],"correct":"A","explanation":{"en":"The regimen includes an induction phase followed by six months of maintenance suppression.","ar":"يتضمن النظام مرحلة استهلالية ثم تثبيطًا وقائيًا لمدة ستة أشهر."},"reasoning":{"en":"The purpose is sustained symptom suppression, not guaranteed eradication of colonization.","ar":"الهدف هو تثبيط الأعراض المستمر وليس ضمان القضاء على الاستعمار."},"image":null},{"id":"Q138","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"Treatment","difficulty":"Hard","source":"PDF p. 93","question":{"en":"What is first-line management of typical candidal intertrigo?","ar":"ما علاج الخط الأول لالتهاب الثنيات المعتاد بالمبيضات؟"},"options":[{"letter":"A","en":"Topical azole or nystatin plus drying, barrier protection, and risk-factor control","ar":"أزول موضعي أو نيستاتين مع التجفيف والحاجز وضبط عوامل الخطورة"},{"letter":"B","en":"Systemic antibiotics alone","ar":"مضادات حيوية جهازية وحدها"},{"letter":"C","en":"Potent steroid under occlusion","ar":"كورتيزون قوي تحت غطاء"},{"letter":"D","en":"Oral terbinafine as mandatory first line","ar":"تيربينافين فموي كخط أول إلزامي"}],"correct":"A","explanation":{"en":"Treatment must address both Candida and the moist, frictional environment that supports it.","ar":"يجب أن يعالج العلاج Candida والبيئة الرطبة الاحتكاكية التي تدعمها معًا."},"reasoning":{"en":"Drug-only therapy often relapses if maceration and metabolic risks remain.","ar":"غالبًا ينتكس العلاج الدوائي وحده إذا استمرت الرطوبة وعوامل الخطورة الأيضية."},"image":null},{"id":"Q139","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"Treatment","difficulty":"Medium","source":"PDF p. 94","question":{"en":"Which plan is most appropriate for candidal angular cheilitis associated with dentures?","ar":"أي خطة أنسب لالتهاب زاوية الفم بالمبيضات المرتبط بطقم الأسنان؟"},"options":[{"letter":"A","en":"Topical azole, barrier emollient, and correction/disinfection of dentures","ar":"أزول موضعي ومرطب حاجز وتصحيح/تطهير طقم الأسنان"},{"letter":"B","en":"Topical steroid alone indefinitely","ar":"كورتيزون موضعي وحده دون نهاية"},{"letter":"C","en":"Ignore denture hygiene","ar":"تجاهل نظافة طقم الأسنان"},{"letter":"D","en":"IV antifungal for every case","ar":"مضاد فطري وريدي لكل الحالات"}],"correct":"A","explanation":{"en":"Local antifungal therapy works best when saliva pooling and denture reservoirs are corrected.","ar":"يعمل العلاج الموضعي بصورة أفضل عند تصحيح تجمع اللعاب ومستودع طقم الأسنان."},"reasoning":{"en":"Persistent mechanical and microbial reservoirs explain common recurrence.","ar":"تفسر المستودعات الميكانيكية والميكروبية استمرار التكرار."},"image":null},{"id":"Q140","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"Treatment","difficulty":"Hard","source":"PDF p. 87","question":{"en":"Confirmed symptomatic C. glabrata VVC persists after azole therapy in a nonpregnant patient. Which regimen is a recognized option?","ar":"استمر التهاب مهبل عرضي مؤكد بـ C. glabrata بعد الأزول لدى مريضة غير حامل. أي نظام يعد خيارًا معروفًا؟"},"options":[{"letter":"A","en":"Boric acid 600 mg intravaginally nightly for 14–21 days","ar":"حمض بوريك 600 مجم مهبليًا ليلًا لمدة 14–21 يومًا"},{"letter":"B","en":"Oral boric acid 600 mg","ar":"حمض بوريك 600 مجم فمويًا"},{"letter":"C","en":"Fluconazole single dose in every resistant case","ar":"جرعة فلوكونازول واحدة في كل حالة مقاومة"},{"letter":"D","en":"No confirmation or counseling needed","ar":"لا حاجة للتأكيد أو التوعية"}],"correct":"A","explanation":{"en":"Boric acid is an option for confirmed azole-resistant non-albicans infection in nonpregnant patients, with strict toxicity counseling.","ar":"حمض البوريك خيار للعدوى المؤكدة المقاومة للأزول بغير الألبكان لدى غير الحوامل مع توعية صارمة بالسمية."},"reasoning":{"en":"The treatment is species-specific, route-specific, and pregnancy-restricted.","ar":"العلاج خاص بالنوع وطريق الاستخدام وممنوع في الحمل."},"image":null},{"id":"Q141","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"Image","difficulty":"Hard","source":"PDF p. 96","question":{"en":"The image shows white curd-like oral plaques on an erythematous mucosal background. What is the diagnosis?","ar":"توضح الصورة لويحات فموية بيضاء متجبنة فوق مخاطية حمراء. ما التشخيص؟"},"options":[{"letter":"A","en":"Oral candidiasis","ar":"داء المبيضات الفموي"},{"letter":"B","en":"Tinea cruris","ar":"سعفة الأرفاغ"},{"letter":"C","en":"Tinea nigra","ar":"السعفة السوداء"},{"letter":"D","en":"Onychomycosis","ar":"فطار الأظافر"}],"correct":"A","explanation":{"en":"The removable curd-like plaques are characteristic of thrush.","ar":"اللويحات المتجبنة القابلة للإزالة تميز القلاع الفموي."},"reasoning":{"en":"The mucosal site and pseudomembranous appearance are diagnostic clues.","ar":"الموقع المخاطي والمظهر الغشائي الكاذب دليلان تشخيصيان."},"image":"assets/images/chapters/fungal/fungal-q141.webp"},{"id":"Q142","topic":"candidiasis","topicEn":"Candidiasis","topicAr":"داء المبيضات","type":"Image","difficulty":"Hard","source":"PDF p. 96","question":{"en":"The image shows an inflamed moist fold with small peripheral satellite lesions. Which diagnosis is most likely?","ar":"توضح الصورة ثنية رطبة ملتهبة مع آفات صغيرة تابعة على الأطراف. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Candidal intertrigo","ar":"التهاب الثنيات بالمبيضات"},{"letter":"B","en":"Tinea capitis","ar":"سعفة الرأس"},{"letter":"C","en":"Tinea nigra","ar":"السعفة السوداء"},{"letter":"D","en":"White superficial onychomycosis","ar":"فطار الأظافر الأبيض السطحي"}],"correct":"A","explanation":{"en":"Moist erythema in a fold with satellite papules or pustules is typical of Candida.","ar":"الحمامى الرطبة في ثنية مع حطاطات أو بثور تابعة نموذجية للكانديدا."},"reasoning":{"en":"The satellite pattern is more specific than redness alone.","ar":"نمط الآفات التابعة أكثر نوعية من الاحمرار وحده."},"image":"assets/images/chapters/fungal/fungal-q142.webp"},{"id":"Q143","topic":"tinea-nigra","topicEn":"Tinea Nigra","topicAr":"السعفة السوداء","type":"MCQ","difficulty":"Easy","source":"PDF p. 97","question":{"en":"Which organism causes tinea nigra?","ar":"ما الكائن المسبب للسعفة السوداء؟"},"options":[{"letter":"A","en":"Hortaea werneckii","ar":"Hortaea werneckii"},{"letter":"B","en":"Malassezia furfur","ar":"Malassezia furfur"},{"letter":"C","en":"Trichophyton tonsurans","ar":"Trichophyton tonsurans"},{"letter":"D","en":"Candida albicans","ar":"Candida albicans"}],"correct":"A","explanation":{"en":"Tinea nigra is a superficial infection caused by the dematiaceous fungus Hortaea werneckii.","ar":"السعفة السوداء عدوى سطحية يسببها الفطر الداكن Hortaea werneckii."},"reasoning":{"en":"The pigment-producing organism explains the brown-black macule.","ar":"يفسر الكائن المنتج للصبغة ظهور البقعة البنية السوداء."},"image":null},{"id":"Q144","topic":"tinea-nigra","topicEn":"Tinea Nigra","topicAr":"السعفة السوداء","type":"MCQ","difficulty":"Easy","source":"PDF p. 97","question":{"en":"What is the most typical clinical presentation of tinea nigra?","ar":"ما العرض السريري الأكثر شيوعًا للسعفة السوداء؟"},"options":[{"letter":"A","en":"A unilateral asymptomatic brown-black macule on a palm","ar":"بقعة بنية سوداء أحادية غير عرضية على راحة اليد"},{"letter":"B","en":"Painful boggy scalp swelling","ar":"تورم مؤلم إسفنجي بفروة الرأس"},{"letter":"C","en":"Moist groin plaque with satellite pustules","ar":"لويحة رطبة بالأربية مع بثور تابعة"},{"letter":"D","en":"Thick destroyed toenail","ar":"ظفر قدم سميك ومدمر"}],"correct":"A","explanation":{"en":"Tinea nigra usually presents as a slowly enlarging, noninflammatory pigmented macule on the palm or sole.","ar":"تظهر السعفة السوداء عادةً كبقعة مصطبغة بطيئة التوسع وغير ملتهبة على راحة اليد أو أخمص القدم."},"reasoning":{"en":"The absence of symptoms and scale can make it resemble a melanocytic lesion.","ar":"قد يجعل غياب الأعراض والقشور الآفة تشبه الآفات الميلانينية."},"image":null},{"id":"Q145","topic":"tinea-nigra","topicEn":"Tinea Nigra","topicAr":"السعفة السوداء","type":"Case","difficulty":"Easy","source":"PDF p. 97","question":{"en":"A healthy traveler develops a slowly enlarging, sharply defined brown macule on one palm. It is asymptomatic and does not follow skin lines on dermoscopy. What is most likely?","ar":"مسافر سليم ظهرت لديه بقعة بنية محددة وبطيئة التوسع على راحة يد واحدة، بلا أعراض ولا تتبع خطوط الجلد بالمنظار. ما الأرجح؟"},"options":[{"letter":"A","en":"Tinea nigra","ar":"السعفة السوداء"},{"letter":"B","en":"Kerion","ar":"الكيريون"},{"letter":"C","en":"Candidal intertrigo","ar":"التهاب الثنيات بالمبيضات"},{"letter":"D","en":"Pityriasis versicolor","ar":"النخالية المبرقشة"}],"correct":"A","explanation":{"en":"A unilateral noninflammatory acral pigmented macule with brown spicules not following dermatoglyphics is typical.","ar":"البقعة المصطبغة الأحادية غير الملتهبة مع شوكات بنية لا تتبع خطوط الجلد نموذجية."},"reasoning":{"en":"The benign fungal pattern must still be distinguished from melanocytic disease.","ar":"يجب مع ذلك تمييز النمط الفطري الحميد عن المرض الميلانيني."},"image":null},{"id":"Q146","topic":"tinea-nigra","topicEn":"Tinea Nigra","topicAr":"السعفة السوداء","type":"Case","difficulty":"Hard","source":"PDF p. 97","question":{"en":"A black palmar macule is suspected to be tinea nigra. Which KOH finding would support the diagnosis?","ar":"يُشتبه أن بقعة سوداء براحة اليد هي سعفة سوداء. أي نتيجة KOH تدعم التشخيص؟"},"options":[{"letter":"A","en":"Pigmented septate branched hyphae with blastoconidia","ar":"خيوط مصطبغة مقسمة ومتفرعة مع خلايا برعمية"},{"letter":"B","en":"Only budding nonpigmented yeast without hyphae","ar":"خميرة غير مصطبغة متبرعمة فقط دون خيوط"},{"letter":"C","en":"Acid-fast bacilli","ar":"عصيات مقاومة للحمض"},{"letter":"D","en":"No fungal elements in every case","ar":"غياب العناصر الفطرية في كل الحالات"}],"correct":"A","explanation":{"en":"Direct microscopy can show brown septate branching hyphae and yeast-like cells.","ar":"يمكن للفحص المباشر إظهار خيوط بنية مقسمة ومتفرعة وخلايا شبيهة بالخميرة."},"reasoning":{"en":"Pigmentation in the organism matches the lesion’s color.","ar":"يتوافق تصبغ الكائن مع لون الآفة."},"image":null},{"id":"Q147","topic":"tinea-nigra","topicEn":"Tinea Nigra","topicAr":"السعفة السوداء","type":"Treatment","difficulty":"Medium","source":"PDF p. 97","question":{"en":"What is an appropriate first-line treatment for tinea nigra?","ar":"ما علاج الخط الأول المناسب للسعفة السوداء؟"},"options":[{"letter":"A","en":"Topical azole applied for about 2–3 weeks","ar":"أزول موضعي لمدة نحو 2–3 أسابيع"},{"letter":"B","en":"IV amphotericin B","ar":"أمفوتيريسين ب وريدي"},{"letter":"C","en":"Oral antibiotic","ar":"مضاد حيوي فموي"},{"letter":"D","en":"Potent topical steroid alone","ar":"كورتيزون موضعي قوي وحده"}],"correct":"A","explanation":{"en":"The infection is confined to the stratum corneum and usually responds rapidly to topical azoles or keratolytic antifungals.","ar":"تقتصر العدوى على الطبقة القرنية وتستجيب عادةً سريعًا للأزولات الموضعية أو العلاجات الحالّة للكيراتين."},"reasoning":{"en":"Superficial localization makes systemic therapy unnecessary in typical cases.","ar":"الموقع السطحي يجعل العلاج الجهازي غير ضروري في الحالات المعتادة."},"image":null},{"id":"Q148","topic":"tinea-nigra","topicEn":"Tinea Nigra","topicAr":"السعفة السوداء","type":"Treatment","difficulty":"Medium","source":"PDF p. 97","question":{"en":"A patient with tinea nigra has marked palmar hyperhidrosis and repeated recurrence. What additional measure is most useful?","ar":"مريض لديه سعفة سوداء مع فرط تعرق شديد براحة اليد وتكرار العدوى. ما الإجراء الإضافي الأكثر فائدة؟"},"options":[{"letter":"A","en":"Treat the hyperhidrosis and reduce moisture","ar":"علاج فرط التعرق وتقليل الرطوبة"},{"letter":"B","en":"Apply occlusive gloves continuously","ar":"ارتداء قفازات مغلقة باستمرار"},{"letter":"C","en":"Use topical steroid prophylaxis","ar":"استخدام كورتيزون موضعي وقائي"},{"letter":"D","en":"Take antibiotics monthly","ar":"تناول مضادات حيوية شهريًا"}],"correct":"A","explanation":{"en":"Moisture promotes persistence; controlling sweating reduces the local conditions favoring recurrence.","ar":"تدعم الرطوبة استمرار العدوى، ويساعد التحكم في التعرق على تقليل البيئة المهيئة للتكرار."},"reasoning":{"en":"Recurrence prevention requires correction of the local ecological factor.","ar":"تتطلب الوقاية من التكرار تصحيح العامل البيئي الموضعي."},"image":null},{"id":"Q149","topic":"tinea-nigra","topicEn":"Tinea Nigra","topicAr":"السعفة السوداء","type":"Treatment","difficulty":"Easy","source":"PDF p. 97","question":{"en":"A pigmented palmar lesion has atypical features and recent rapid change. What should be done before treating it as tinea nigra?","ar":"آفة مصطبغة براحة اليد لها علامات غير نمطية وتغير سريع حديث. ماذا يجب فعله قبل علاجها كسعفة سوداء؟"},"options":[{"letter":"A","en":"Exclude a melanocytic lesion with appropriate dermatologic assessment","ar":"استبعاد آفة ميلانينية بتقييم جلدي مناسب"},{"letter":"B","en":"Assume all palmar pigmentation is fungal","ar":"اعتبار كل تصبغ راحي فطريًا"},{"letter":"C","en":"Use steroid and wait","ar":"استخدام كورتيزون والانتظار"},{"letter":"D","en":"Scrape deeply without assessment","ar":"الكشط العميق دون تقييم"}],"correct":"A","explanation":{"en":"Tinea nigra can mimic acral melanocytic lesions, and atypical evolution warrants diagnostic caution.","ar":"قد تشبه السعفة السوداء الآفات الميلانينية الطرفية، ويستدعي التطور غير النمطي الحذر التشخيصي."},"reasoning":{"en":"The harm of missing melanoma is greater than the inconvenience of confirming a superficial fungus.","ar":"ضرر تفويت الميلانوما أكبر من عبء تأكيد عدوى فطرية سطحية."},"image":null},{"id":"Q150","topic":"tinea-nigra","topicEn":"Tinea Nigra","topicAr":"السعفة السوداء","type":"Image","difficulty":"Medium","source":"PDF p. 97","question":{"en":"The image shows a unilateral, sharply demarcated brown-black macule on the palm without inflammation. What is the most likely diagnosis?","ar":"توضح الصورة بقعة بنية سوداء أحادية محددة على راحة اليد دون التهاب. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Tinea nigra","ar":"السعفة السوداء"},{"letter":"B","en":"Pityriasis versicolor","ar":"النخالية المبرقشة"},{"letter":"C","en":"Tinea capitis","ar":"سعفة الرأس"},{"letter":"D","en":"Candidal intertrigo","ar":"التهاب الثنيات بالمبيضات"}],"correct":"A","explanation":{"en":"The acral site, pigment, sharp border, and lack of inflammation are typical of tinea nigra.","ar":"الموقع الطرفي واللون والحد الواضح وغياب الالتهاب علامات نموذجية للسعفة السوداء."},"reasoning":{"en":"The image pattern is suggestive, but atypical lesions still require exclusion of melanocytic disease.","ar":"نمط الصورة مرجح، لكن الآفات غير النمطية تحتاج مع ذلك استبعاد المرض الميلانيني."},"image":"assets/images/chapters/fungal/fungal-q150.webp"}]);
